security_findings.evidence:
UNPATCHED pseudocode showing the vulnerable arithmetic:

  // At 0x1c000209b: unsaturating addition
  if (1 & arg4)
      r10 += *(arg1 + (rax << 3) + 0xb0);     // no overflow check

  // At 0x1c00020cf/0x20c3/0x20ba: unsaturating additions
  if (!arg2)
      r10 += *(arg1 + 0x98);                   // no overflow check
  else if (arg2 == 1)
      r10 += *(arg1 + 0xa0);                   // no overflow check
  else if (arg2 == 2)
      r10 += *(arg1 + 0xa8);                   // no overflow check

  // At 0x1c0002110: truncating multiply
  imul    rcx, r10, 0x989680   // overflows 64-bit when r10 > ~1.8TB
  mul     rcx                   // then used in division
  ...
  cmp     r8, rcx               // throttling decision with overflowed value
  jb      0x1c00021b5          // if r8 < overflowed_rcx -> not depleted

  // At 0x1c0002175: truncating multiply
  mov     r9, r10
  sub     r9, r8
  imul    r9, rax               // overflows, wraps to small value

PATCHED pseudocode showing the fix:
  // Saturating addition:
  int64_t r9_1 = *(arg1 + (rax << 3) + 0xb0) + r10;
  if (r9_1 >= r10) rax_1 = r9_1;
  if (r9_1 < r10)  rax_1 = -1;   // saturate on overflow

  // Overflow-safe multiply:
  rdx_1 = HIGHQ(0x989680 * r10);    // check high 64 bits
  rax_6 = LOWQ(0x989680 * r10);
  if (!rdx_1) rcx_4 = rax_6;        // no overflow -> use result
  // else rcx_4 stays 0x3b9aca00 (1e9 cap)
